StoreGoodsConfig = {}
StoreGoodsConfig.GoodsList = {}

function StoreGoodsConfig:initConfig(goodsList)
    for _, goods in pairs(goodsList) do
        local item = {}
        item.GoodsId = tonumber(goods.GoodsId)
        item.TabId = tonumber(goods.TabId)
        item.Reward = RewardConfig:getRewardById(tonumber(goods.RewardId))
        item.ItemId = item.Reward.RewardId
        item.Count = item.Reward.Count
        item.MoneyType = tonumber(goods.MoneyType)
        item.Price = tonumber(goods.Price)
        item.PriceA = tonumber(goods.PriceA)
        item.PriceB = tonumber(goods.PriceB)
        item.PriceC = tonumber(goods.PriceC)
        self.GoodsList[item.GoodsId] = item
    end

end

function StoreGoodsConfig:getGoodsById(goodsId)
    return self.GoodsList[goodsId]
end

function StoreGoodsConfig:getRewardByGoodsId(goodsId)
    for _, v in pairs(self.GoodsList) do
        if v.GoodsId == goodsId then
            return v.Reward
        end
    end
end

return StoreGoodsConfig